import subprocess
import re

def get_wifi_networks():
    """Get available WiFi networks using netsh (Windows)."""
    try:
        result = subprocess.run(
            ['netsh', 'wlan', 'show', 'networks', 'mode=bssid'],
            capture_output=True, text=True, timeout=30
        )
        return result.stdout
    except Exception as e:
        return f"Error: {e}"

def analyze_network_security(output):
    """Analyze networks for security issues."""
    networks = []
    current_network = {}

    for line in output.split('\n'):
        line = line.strip()

        if 'SSID' in line and 'BSSID' not in line:
            if current_network:
                networks.append(current_network)
            ssid = line.split(':', 1)[1].strip()
            current_network = {'ssid': ssid, 'security': 'Open'}

        elif 'Authentication' in line:
            auth = line.split(':', 1)[1].strip()
            current_network['security'] = auth

        elif 'Encryption' in line:
            enc = line.split(':', 1)[1].strip()
            current_network['encryption'] = enc

    if current_network:
        networks.append(current_network)

    return networks

def generate_security_report(networks):
    """Generate security report with risk assessment."""
    print("=" * 60)
    print("WIRELESS NETWORK SECURITY REPORT")
    print("=" * 60)

    open_networks = []
    weak_networks = []
    secure_networks = []

    for net in networks:
        security = net.get('security', '').lower()

        if 'open' in security:
            open_networks.append(net)
        elif 'wep' in security:
            weak_networks.append(net)
        else:
            secure_networks.append(net)

    print(f"\nTotal Networks Found: {len(networks)}")
    print(f"Secure (WPA/WPA2/WPA3): {len(secure_networks)}")
    print(f"Weak (WEP): {len(weak_networks)}")
    print(f"Open (No Encryption): {len(open_networks)}")

    print("\n" + "-" * 60)
    print("VULNERABLE NETWORKS:")
    print("-" * 60)

    if open_networks:
        print("\n🚨 CRITICAL - Open Networks (Avoid These):")
        for net in open_networks:
            print(f"   - {net['ssid']}")

    if weak_networks:
        print("\n⚠️  WARNING - Weak Encryption (WEP):")
        for net in weak_networks:
            print(f"   - {net['ssid']}")

    if not open_networks and not weak_networks:
        print("\n✓ No vulnerable networks detected.")

    return {
        'total': len(networks),
        'secure': len(secure_networks),
        'weak': len(weak_networks),
        'open': len(open_networks)
    }

# Main execution
if __name__ == "__main__":
    print("Scanning for WiFi networks...\n")
    output = get_wifi_networks()

    if 'Error' in output:
        print("Could not scan networks. Run as administrator.")
    else:
        networks = analyze_network_security(output)
        report = generate_security_report(networks)

import ssl
import socket
import datetime
from urllib.parse import urlparse

class SSLCertificateValidator:
    """Validate SSL/TLS certificates for secure communications."""

    def __init__(self, hostname, port=443):
        self.hostname = hostname
        self.port = port
        self.certificate = None
        self.validation_results = []

    def fetch_certificate(self):
        """Retrieve SSL certificate from server."""
        try:
            context = ssl.create_default_context()
            context.check_hostname = False
            context.verify_mode = ssl.CERT_NONE

            with socket.create_connection((self.hostname, self.port), timeout=10) as sock:
                with context.wrap_socket(sock, server_hostname=self.hostname) as ssock:
                    self.certificate = ssock.getpeercert()
                    return True
        except ssl.SSLCertVerificationError as e:
            self.validation_results.append({
                'check': 'Certificate Validation',
                'status': 'FAIL',
                'message': f'Certificate verification failed: {str(e)}'
            })
            return False
        except Exception as e:
            self.validation_results.append({
                'check': 'Connection',
                'status': 'FAIL',
                'message': f'Failed to connect: {str(e)}'
            })
            return False

        return True if self.certificate else False

    def check_expiration(self):
        """Check if certificate is expired or expiring soon."""
        if not self.certificate:
            return

        # Parse notAfter date
        not_after = self.certificate.get('notAfter', '')
        try:
            expiry_date = datetime.datetime.strptime(not_after, '%b %d %H:%M:%S %Y %Z')
            days_until_expiry = (expiry_date - datetime.datetime.now()).days

            if days_until_expiry < 0:
                self.validation_results.append({
                    'check': 'Certificate Expiration',
                    'status': 'FAIL',
                    'message': f'Certificate EXPIRED on {expiry_date.strftime("%Y-%m-%d")}'
                })
            elif days_until_expiry < 30:
                self.validation_results.append({
                    'check': 'Certificate Expiration',
                    'status': 'WARNING',
                    'message': f'Certificate expires in {days_until_expiry} days'
                })
            else:
                self.validation_results.append({
                    'check': 'Certificate Expiration',
                    'status': 'PASS',
                    'message': f'Certificate valid for {days_until_expiry} more days'
                })
        except ValueError:
            self.validation_results.append({
                'check': 'Certificate Expiration',
                'status': 'WARNING',
                'message': 'Could not parse expiration date'
            })

    def check_signature_algorithm(self):
        """Check certificate signature algorithm for weaknesses."""
        if not self.certificate:
            return

        subject = dict(x[0] for x in self.certificate.get('subject', []))
        issuer = dict(x[0] for x in self.certificate.get('issuer', []))

        # Check for weak algorithms (SHA1, MD5)
        signature_alg = self.certificate.get('signatureAlgorithm', '').lower()

        if 'sha1' in signature_alg or 'md5' in signature_alg:
            self.validation_results.append({
                'check': 'Signature Algorithm',
                'status': 'FAIL',
                'message': f'Weak signature algorithm detected: {signature_alg}'
            })
        elif 'sha256' in signature_alg or 'sha384' in signature_alg or 'sha512' in signature_alg:
            self.validation_results.append({
                'check': 'Signature Algorithm',
                'status': 'PASS',
                'message': f'Secure signature algorithm: {signature_alg}'
            })
        else:
            self.validation_results.append({
                'check': 'Signature Algorithm',
                'status': 'WARNING',
                'message': f'Unknown signature algorithm: {signature_alg}'
            })

    def check_key_strength(self):
        """Check public key strength."""
        if not self.certificate:
            return

        # Check for weak key sizes
        public_key = self.certificate.get('subjectPublicKeyInfo', {})
        bits = public_key.get('bits', 0)

        if bits < 2048:
            self.validation_results.append({
                'check': 'Key Strength',
                'status': 'FAIL',
                'message': f'Weak key size: {bits} bits (minimum 2048 recommended)'
            })
        elif bits >= 2048:
            self.validation_results.append({
                'check': 'Key Strength',
                'status': 'PASS',
                'message': f'Adequate key size: {bits} bits'
            })

    def check_self_signed(self):
        """Check if certificate is self-signed."""
        if not self.certificate:
            return

        subject = dict(x[0] for x in self.certificate.get('subject', []))
        issuer = dict(x[0] for x in self.certificate.get('issuer', []))

        subject_cn = subject.get('commonName', '')
        issuer_cn = issuer.get('commonName', '')

        if subject_cn == issuer_cn:
            self.validation_results.append({
                'check': 'Certificate Authority',
                'status': 'WARNING',
                'message': 'Self-signed certificate detected'
            })
        else:
            self.validation_results.append({
                'check': 'Certificate Authority',
                'status': 'PASS',
                'message': f'Issued by: {issuer_cn}'
            })

    def validate(self):
        """Run all validation checks."""
        print(f"\n{'='*60}")
        print(f"SSL/TLS CERTIFICATE VALIDATION: {self.hostname}")
        print(f"{'='*60}")

        if not self.fetch_certificate():
            print("\n❌ Could not retrieve certificate")
            for result in self.validation_results:
                print(f"  {result['check']}: {result['message']}")
            return

        # Run all checks
        self.check_expiration()
        self.check_signature_algorithm()
        self.check_key_strength()
        self.check_self_signed()

        # Display results
        print(f"\n{'Validation Check':<30} {'Status':<10} {'Details'}")
        print("-" * 70)

        pass_count = fail_count = warning_count = 0

        for result in self.validation_results:
            status_icon = {
                'PASS': '✓',
                'FAIL': '✗',
                'WARNING': '⚠'
            }.get(result['status'], '?')

            print(f"{result['check']:<30} {status_icon} {result['status']:<6} {result['message']}")

            if result['status'] == 'PASS':
                pass_count += 1
            elif result['status'] == 'FAIL':
                fail_count += 1
            else:
                warning_count += 1

        # Summary
        print("\n" + "=" * 60)
        print("SECURITY SUMMARY:")
        print("=" * 60)
        print(f"  ✓ Passed: {pass_count}")
        print(f"  ⚠ Warnings: {warning_count}")
        print(f"  ✗ Failed: {fail_count}")

        if fail_count > 0:
            print("\n🔴 RECOMMENDATION: Do not trust this connection!")
            print("   The certificate has critical security issues.")
        elif warning_count > 0:
            print("\n🟡 RECOMMENDATION: Proceed with caution.")
            print("   Review warnings before proceeding.")
        else:
            print("\n🟢 RECOMMENDATION: Connection appears secure.")

# Example usage
if __name__ == "__main__":
    # Test with known secure and insecure sites
    test_domains = [
        'www.google.com',
        'expired.badssl.com',
        'self-signed.badssl.com'
    ]

    for domain in test_domains:
        validator = SSLCertificateValidator(domain)
        validator.validate()
        print("\n")
